import jieba
import sys

names = ["曹操", "刘备", "孙权", "诸葛亮", "孔明", "关羽", "云长", "张飞", "翼德", "赵云", "子龙", "马超", "孟起", "黄忠", "汉升", "周瑜", "公瑾","吕布","玄德", "华雄", "颜良", "文丑", "周郎", "仲谋", "许褚", "夏侯渊"]

cnt = {}

words = jieba.lcut(sys.stdin.read())

for word in words:
    if word in names:
        cnt[word] = cnt.get(word, 0) + 1

for i,j in cnt.items():
    print(f"{i}: {j}")
